<?php namespace App\Repositories\Timetable;use App\Repositories\BaseRepository;use App\Models\Timetable\Timetable;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class TimetableRepository extends BaseRepository{    public function __construct(Timetable $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySection(int $sectionId): Collection    {        return $this->findByField('section_id', $sectionId);    }    public function findByDay(string $day): Collection    {        return $this->findByField('day', $day);    }    public function findByClassSectionDay(int $classId, int $sectionId, string $day): ?Timetable    {        return $this->query()->where('class_id', $classId)->where('section_id', $sectionId)->where('day', $day)->first();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByTeacher(int $employeeId): Collection    {        return $this->query()->whereHas('periods', function ($q) use ($employeeId) {                $q->where('employee_id', $employeeId);            })->get();    }    public function getActiveTimetables(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function cloneTimetable(int $sourceId, int $targetClassId, int $targetSectionId): ?Timetable    {        $source = $this->getById($sourceId);        $clone = $this->create([            'class_id' => $targetClassId,            'section_id' => $targetSectionId,            'academic_year_id' => $source->academic_year_id,            'day' => $source->day,            'is_active' => true,        ]);        if ($source->relationLoaded('periods')) {            foreach ($source->periods as $period) {                $period->replicate()->fill(['timetable_id' => $clone->id])->save();            }        }        return $clone;    }}